// ── Stage 19: capability/cnode lifetime audit + cap_refcount symmetry ─────────

#[test]
fn cap_refcount_increment_on_mint() {
    // mint_capability_in_cnode must increment cap_refcount to 1 for a freshly
    // created MemoryObject that had cap_refcount=0 before the mint.
    let mut state = Bootstrap::init().expect("init");
    // alloc_anonymous_memory_object calls mint_capability_in_cnode internally and
    // returns the (id, cap) pair.  cap_refcount must be 1 after the alloc.
    let (mo_id, _cap) = state.alloc_anonymous_memory_object().expect("alloc");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1,
        "cap_refcount must be 1 immediately after mint"
    );
}

#[test]
fn cap_refcount_decrement_on_revoke() {
    // revoke_capability_in_cnode must decrement cap_refcount back to 0 and
    // reclaim the MemoryObject slot.
    let mut state = Bootstrap::init().expect("init");
    let (mo_id, cap) = state.alloc_anonymous_memory_object().expect("alloc");
    let cnode = state.current_task_cnode().expect("cnode");

    let slot = state
        .memory_object_slot_by_id(mo_id)
        .expect("slot before revoke");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1
    );

    state
        .revoke_capability_in_cnode(cnode, cap)
        .expect("revoke");

    // cap_refcount reached 0 → MemoryObject must be reclaimed.
    assert!(
        state.memory_object_slot_by_id(mo_id).is_none(),
        "MemoryObject must be reclaimed when cap_refcount reaches 0"
    );
}

#[test]
fn reply_cap_mint_does_not_increment_memory_object_refcount() {
    // Reply caps reference a CapObject::Reply{index, generation}, NOT a
    // MemoryObject.  adjust_memory_object_cap_refcount must be a no-op for
    // non-MemoryObject cap objects.  Minting a Reply cap must not change any
    // MemoryObject's cap_refcount.
    let mut state = Bootstrap::init().expect("init");

    // Create a MemoryObject so we can observe its cap_refcount.
    let (mo_id, _mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    let refcount_before = state.memory.memory_objects[slot].expect("obj").cap_refcount;

    // Create an endpoint so we have a valid RECEIVE cap for create_reply_cap_for_caller.
    let (_eid, _send_cap, recv_cap) = state.create_endpoint(1).expect("endpoint");

    // Mint a Reply cap into the current task's cnode (simulates ipc_call path).
    let _reply_cap = state
        .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
        .expect("reply cap created");

    // The MemoryObject's cap_refcount must be unchanged — Reply caps have no MemoryObject.
    let refcount_after = state.memory.memory_objects[slot].expect("obj").cap_refcount;
    assert_eq!(
        refcount_after, refcount_before,
        "minting a Reply cap must not change MemoryObject cap_refcount"
    );
}

#[test]
fn revoke_reply_cap_record_clears_global_slot() {
    // revoke_reply_caps_for_caller must clear all global ReplyCapRecord slots
    // whose caller_tid matches the given tid.
    let mut state = Bootstrap::init().expect("init");
    let (_eid, _send_cap, recv_cap) = state.create_endpoint(1).expect("endpoint");

    // Mint a Reply cap — this inserts a ReplyCapRecord for caller_tid=0.
    let _reply_cap = state
        .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
        .expect("reply cap");

    // Revoke all reply cap records for caller 0.
    let revoked = state.revoke_reply_caps_for_caller(0);
    assert_eq!(revoked, 1, "must revoke exactly one reply cap record");

    // A second call must return 0 (already cleared).
    let revoked_again = state.revoke_reply_caps_for_caller(0);
    assert_eq!(
        revoked_again, 0,
        "second revoke of already-cleared slot must return 0"
    );
}

#[test]
fn task_exit_clears_reply_cap_records() {
    // When a caller task exits, mark_task_dead → exit_task path calls
    // revoke_reply_caps_for_caller so that stale ReplyCapRecords pointing to
    // the exited task are not left in the global array.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");

    let (_eid, _send_cap, recv_cap) = state.create_endpoint(1).expect("endpoint");

    // Mint a Reply cap for caller = task 0.
    let _reply_cap = state
        .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
        .expect("reply cap");

    // Exit task 0 (the caller).
    state.exit_task(0, 0).expect("exit");

    // After exit, revoke_reply_caps_for_caller for tid=0 must return 0 because
    // exit_task already cleared the records.
    let remaining = state.revoke_reply_caps_for_caller(0);
    assert_eq!(
        remaining, 0,
        "exit_task must clear reply cap records for the exiting task"
    );
}

#[test]
fn cnode_teardown_releases_all_cap_refcounts() {
    // mark_task_dead triggers maybe_cleanup_process_cnode_for_pid which calls
    // revoke_capability_in_cnode for every live slot.  revoke_capability_in_cnode
    // cascades to delegated descendants — revoking the source cap also revokes the
    // destination cap, applying two cap_refcount decrements.
    //
    // Invariant: after the source holder is marked dead:
    //   - Source cap's cap_refcount decrement applied (−1).
    //   - Delegated cap in dest cnode also revoked (−1).
    //   - Total cap_refcount reaches 0 → MemoryObject is reclaimed.
    //
    // Note: exit_task sets status to Exited (not Dead) so maybe_cleanup_process_cnode_for_pid
    // would skip it; mark_task_dead sets status Dead and calls the cleanup directly.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");

    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    // Grant cap to task 1 so task 1's cnode holds a reference.
    let _cap_t1 = state
        .grant_capability_task_to_task(0, mem_cap, 1)
        .expect("grant to task1");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "source + delegated cap → cap_refcount must be 2"
    );

    // mark_task_dead: sets Dead status, then calls maybe_cleanup_process_cnode_for_pid.
    // revoke_capability_in_cnode cascades: source revoke also revokes all
    // delegated descendants (including task1's cap).  Both decrements apply,
    // cap_refcount reaches 0, and the MemoryObject is reclaimed immediately.
    state.mark_task_dead(0).expect("mark task0 dead");

    // cap_refcount is now 0 because revoke_capability_in_cnode cascaded to
    // the delegated cap in task1's cnode.  MemoryObject must be reclaimed.
    assert!(
        state.memory_object_slot_by_id(mo_id).is_none(),
        "MemoryObject must be reclaimed after source-cap revoke cascades to all descendants"
    );
}

#[test]
fn double_revoke_capability_is_safe() {
    // Revoking an already-revoked (empty) cnode slot must return Err, not panic,
    // and must not double-decrement cap_refcount.
    let mut state = Bootstrap::init().expect("init");
    let (mo_id, cap) = state.alloc_anonymous_memory_object().expect("alloc");
    let cnode = state.current_task_cnode().expect("cnode");

    // First revoke: should succeed and reclaim the MemoryObject.
    state
        .revoke_capability_in_cnode(cnode, cap)
        .expect("first revoke");
    assert!(
        state.memory_object_slot_by_id(mo_id).is_none(),
        "reclaimed after first revoke"
    );

    // Second revoke on the same now-empty slot: must return Err(InvalidCapability),
    // not panic, and must not underflow any refcount.
    let result = state.revoke_capability_in_cnode(cnode, cap);
    assert!(
        result.is_err(),
        "second revoke of empty slot must return Err, not panic"
    );
}

#[test]
fn fork_cap_inheritance_increments_refcount() {
    // After fork, both parent and child hold a cap to the same MemoryObject.
    // cap_refcount must be 2 (one from parent's mint, one from child's inherited cap).
    let mut state = Bootstrap::init().expect("init");
    let (parent_asid, _) = state.create_user_address_space().expect("asid");
    state
        .spawn_user_task_from_image(UserImageSpec {
            tid: 51,
            entry: 0x9000,
            asid: Some(parent_asid),
            class: TaskClass::App,
            startup_args: UserImageSpec::DEFAULT_STARTUP_ARGS,
            ..Default::default()
        })
        .expect("parent");
    state
        .yield_current_to(ThreadId(51))
        .expect("switch to task51");

    let (mo_id, _mem_cap) = state.alloc_anonymous_memory_object().expect("mem");

    let slot = state
        .memory_object_slot_by_id(mo_id)
        .expect("slot before fork");
    assert_eq!(
        state.memory.memory_objects[slot].expect("mo").cap_refcount,
        1,
        "cap_refcount must be 1 before fork"
    );

    let _child_tid = state.fork_user_process_cow(51).expect("fork");

    let slot = state
        .memory_object_slot_by_id(mo_id)
        .expect("slot after fork");
    assert_eq!(
        state.memory.memory_objects[slot].expect("mo").cap_refcount,
        2,
        "cap_refcount must be 2 after fork (parent + child cap)"
    );
}

#[test]
fn grant_cap_with_rights_link_fail_decrements_cap_refcount() {
    // When grant_capability_task_to_task_with_rights rolls back because the
    // delegation link table is full, it must decrement cap_refcount back to the
    // pre-grant value.  Without the fix, the fast_revoke_reply_cap_in_cnode call
    // in the rollback path cleared the cnode slot without decrementing refcount,
    // causing a permanent cap_refcount leak.
    std::thread::Builder::new()
        .name("grant_cap_link_fail_rollback_decrements_refcount".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("task1");

            let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");

            // Record the cap_refcount before filling the link table.
            let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
            let refcount_before_grant = state.memory.memory_objects[slot]
                .expect("obj")
                .cap_refcount;

            // Fill the delegation link table with synthetic (unique) entries so
            // that the next record_delegated_capability_link call fails with
            // CapabilityFull.  We use (0, CapId(fake), 1, CapId(fake+1)) pairs
            // with distinct CapId values to bypass the dedup check.
            // hosted-dev uses 4096 slots; freestanding uses 2048.
            let cap_base = 0x8000_0000u64; // outside normal cap range; won't clash
            let mut filled = 0usize;
            loop {
                let src_cap = CapId(cap_base + filled as u64);
                let dst_cap = CapId(cap_base + 0x1_0000_0000 + filled as u64);
                let result = state.record_delegated_capability_link(0, src_cap, 1, dst_cap);
                match result {
                    Ok(()) => {
                        filled += 1;
                    }
                    Err(KernelError::CapabilityFull) => break,
                    Err(e) => panic!("unexpected error filling link table: {e:?}"),
                }
            }
            assert!(filled > 0, "must have filled at least one link slot");

            // Now grant_capability_task_to_task_with_rights will fail at the
            // record_delegated_capability_link step (table full).  The rollback
            // must restore cap_refcount to refcount_before_grant.
            let result = state.grant_capability_task_to_task_with_rights(
                0,
                mem_cap,
                1,
                CapRights::READ | CapRights::MAP,
            );
            assert_eq!(
                result,
                Err(KernelError::CapabilityFull),
                "grant must fail when link table is full"
            );

            // The cap_refcount on the MemoryObject must not have increased.
            let slot = state.memory_object_slot_by_id(mo_id).expect("slot after rollback");
            let refcount_after_rollback = state.memory.memory_objects[slot]
                .expect("obj")
                .cap_refcount;
            assert_eq!(
                refcount_after_rollback, refcount_before_grant,
                "rollback must restore cap_refcount: before={refcount_before_grant} after={refcount_after_rollback}"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

// ── End Stage 19 capability/cnode lifetime audit tests ────────────────────────

// ── Stage 20: IPC cap-transfer / reply-cap / transfer-envelope lifetime ───────

#[test]
fn stage20_transfer_cap_materialize_success_sets_cap_refcount_to_two() {
    // Invariant 3/10: a successful transfer materialization (envelope take + grant
    // into the receiver cnode) leaves the MemoryObject with cap_refcount == 2
    // (sender's original cap + receiver's delegated cap) and consumes the envelope.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1,
        "cap_refcount must be 1 after alloc (sender only)"
    );

    let handle = state
        .stash_transfer_envelope(ThreadId(0), mem_cap, endpoint, Some(ThreadId(1)), None)
        .expect("stash");
    // Take the envelope (recv side) then grant into the receiver's cnode, mirroring
    // materialize_received_transfer_cap.
    let envelope = state
        .take_transfer_envelope(handle, endpoint, ThreadId(1))
        .expect("take");
    let source = state
        .resolve_capability_for_task(envelope.source_tid.0, envelope.source_cap)
        .expect("source cap");
    let derived = state
        .grant_capability_task_to_task_with_rights(
            envelope.source_tid.0,
            envelope.source_cap,
            1,
            source.rights(),
        )
        .expect("grant");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot after");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "cap_refcount must be 2 after transfer materialization"
    );
    // Envelope is consumed: a second take returns None.
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(1))
            .is_none(),
        "envelope must be consumed exactly once"
    );
    // The materialized cap is a fresh slot in the receiver cnode.
    assert!(
        state.task_capability(1, derived).is_some(),
        "receiver must own materialized cap"
    );
}

#[test]
fn stage20_rollback_materialized_transfer_cap_restores_cap_refcount() {
    // Invariant 3/4/12: rolling back a materialized transfer cap removes the cnode
    // slot AND decrements cap_refcount back to the pre-materialization value.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    let before = state.memory.memory_objects[slot].expect("obj").cap_refcount;
    assert_eq!(before, 1);

    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "cap_refcount must be 2 after grant"
    );

    // Roll back as the recv-delivery copy-failure path would.
    let rolled = state.rollback_materialized_recv_cap(1, derived, false);
    assert!(rolled, "transfer-cap rollback must clear a slot");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        before,
        "rollback must restore cap_refcount to pre-grant value"
    );
    assert!(
        state.task_capability(1, derived).is_none(),
        "rolled-back cap must no longer exist in receiver cnode"
    );
}

#[test]
fn stage20_rollback_materialized_transfer_cap_double_call_is_harmless() {
    // Invariant 12: double rollback (slot already cleared) must not underflow and
    // must report no-op without panicking.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");

    assert!(state.rollback_materialized_recv_cap(1, derived, false));
    // Second rollback: slot already gone (and the MemoryObject may be reclaimed).
    let second = state.rollback_materialized_recv_cap(1, derived, false);
    assert!(!second, "second rollback must be a no-op");
    // Source cap still intact, refcount must not be underflowed below 1.
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1,
        "source cap_refcount must remain 1 after double rollback"
    );
}

#[test]
fn stage20_rollback_materialized_reply_cap_clears_slot_and_waiter_id() {
    // Invariant 2/6: rolling back a materialized Reply cap fast-revokes the receiver
    // cnode slot and clears the global waiter_cap_id, while the ReplyCapRecord stays
    // live (the reply was never consumed by the mint).
    std::thread::Builder::new()
        .name("stage20_rollback_reply_cap".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            // create_reply_cap_for_caller mints the Reply cap into the caller's
            // (current task 0) cnode and reserves global slot 0.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            // The reserved global record is at index 0 for a fresh kernel.
            let reply_index = 0usize;
            assert!(state.reply_cap_record_present(reply_index));

            // Simulate materialization: record the caller-local cap as the waiter cap
            // (set_reply_cap_waiter_cap is what the recv path calls).
            let reply_gen = state.with_ipc_state(|ipc| ipc.reply_cap_generations[reply_index]);
            state.set_reply_cap_waiter_cap(reply_index, reply_gen, reply_cap);
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap),
                "waiter_cap_id must be set after materialization"
            );

            // Roll back as a recv-delivery copy failure would.
            let rolled = state.rollback_materialized_recv_cap(0, reply_cap, true);
            assert!(rolled, "reply-cap rollback must clear the cnode slot");
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                None,
                "waiter_cap_id must be cleared after rollback"
            );
            assert!(
                state.reply_cap_record_present(reply_index),
                "ReplyCapRecord must remain live (reply not consumed by mint)"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_reply_cap_double_revoke_is_idempotent() {
    // Invariant 2/12: ipc_reply revokes the one-shot reply cap; a second ipc_reply
    // returns a stable error (InvalidCapability) without panic or underflow.
    std::thread::Builder::new()
        .name("stage20_reply_cap_double_revoke".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            let reply = Message::new(7, b"ok").expect("reply");
            state.ipc_reply(reply_cap, reply).expect("first reply");
            // Drain the delivered reply so the endpoint state is clean.
            let _ = state.ipc_recv(recv_cap).expect("recv");
            // Global record must be consumed.
            assert!(
                !state.reply_cap_record_present(0),
                "ReplyCapRecord must be consumed after ipc_reply"
            );
            let replay = Message::new(7, b"no").expect("replay");
            assert_eq!(
                state.ipc_reply(reply_cap, replay),
                Err(KernelError::InvalidCapability),
                "second ipc_reply on a consumed reply cap must be a stable error"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_clear_reply_cap_waiter_cap_generation_guard() {
    // Invariant 2: clear_reply_cap_waiter_cap is generation-guarded — a stale
    // generation must not disturb a reused record.
    std::thread::Builder::new()
        .name("stage20_clear_waiter_cap_gen_guard".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            let reply_index = 0usize;
            let reply_gen = state.with_ipc_state(|ipc| ipc.reply_cap_generations[reply_index]);
            state.set_reply_cap_waiter_cap(reply_index, reply_gen, reply_cap);
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap)
            );

            // A clear with a stale generation must be ignored.
            state.clear_reply_cap_waiter_cap(reply_index, reply_gen.wrapping_sub(1));
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap),
                "stale-generation clear must be ignored"
            );
            // A clear with the correct generation succeeds.
            state.clear_reply_cap_waiter_cap(reply_index, reply_gen);
            assert_eq!(state.reply_cap_record_waiter_cap(reply_index), None);
        })
        .expect("spawn")
        .join()
        .expect("join");
}

// ── Stage 24 Part B: endpoint / reply-cap revoke + cnode-teardown audit ─────

#[test]
fn stage24_cnode_teardown_with_endpoint_cap_does_not_leave_receiver_waiter() {
    // A task blocked as an endpoint receiver must not be left as a stranded
    // endpoint_waiter after mark_task_dead.  clear_ipc_waiters_for_tid (called by
    // mark_task_dead) clears the receiver waiter slot for the dying tid.
    std::thread::Builder::new()
        .name("stage24_ep_recv_waiter_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("task1");
            let (endpoint_idx, _send_cap, _recv_cap) = state.create_endpoint(4).expect("endpoint");

            // Inject task 1 as the endpoint receiver waiter.
            state.with_ipc_state_mut(|ipc| {
                ipc.endpoint_waiters[endpoint_idx] = Some(ThreadId(1));
            });
            assert_eq!(
                state.endpoint_waiter_count(endpoint_idx),
                1,
                "precondition: task 1 is the endpoint receiver waiter"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.endpoint_waiter_count(endpoint_idx),
                0,
                "mark_task_dead must clear the dead task's endpoint receiver waiter"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_cnode_teardown_with_endpoint_cap_does_not_leave_sender_waiter() {
    // A task blocked as an endpoint sender must not be left as a stranded
    // sender waiter after mark_task_dead.
    std::thread::Builder::new()
        .name("stage24_ep_send_waiter_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("task1");
            let (endpoint_idx, _send_cap, _recv_cap) = state.create_endpoint(4).expect("endpoint");

            let msg = Message::new(0, b"blocked-send").expect("msg");
            state.with_ipc_state_mut(|ipc| {
                ipc.endpoint_sender_waiters[endpoint_idx][0] = Some(SenderWaiter {
                    tid: ThreadId(1),
                    msg,
                });
            });
            assert_eq!(
                state.sender_waiter_count(endpoint_idx),
                1,
                "precondition: task 1 is queued as an endpoint sender waiter"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.sender_waiter_count(endpoint_idx),
                0,
                "mark_task_dead must clear the dead task's endpoint sender waiter"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_reply_cap_cnode_teardown_clears_global_record() {
    // mark_task_dead(caller) calls revoke_reply_caps_for_caller, which clears the
    // global ReplyCapRecord keyed on caller_tid.  After teardown the global slot
    // must be empty (no lingering record referencing a destroyed cnode).
    std::thread::Builder::new()
        .name("stage24_reply_cap_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, None)
                .expect("create reply cap");
            assert!(
                state.reply_cap_record_present(0),
                "precondition: global reply record present for caller tid 1"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert!(
                !state.reply_cap_record_present(0),
                "mark_task_dead(caller) must clear the global reply record"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_stale_reply_cap_cannot_be_reused_after_cnode_teardown() {
    // After the caller is torn down, the Reply CapId held by the replier is stale:
    // the global record is gone, so ipc_reply must return a stable StaleCapability
    // error rather than delivering or panicking.
    std::thread::Builder::new()
        .name("stage24_stale_reply_cap".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            // Reply cap minted into the current (task 0 = replier) cnode.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, None)
                .expect("create reply cap");

            // Caller (task 1) dies: global record cleared by revoke_reply_caps_for_caller.
            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.ipc_reply(reply_cap, Message::new(0, b"stale").expect("msg")),
                Err(KernelError::StaleCapability),
                "stale reply cap after caller teardown must be a stable error"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_endpoint_cap_revoke_does_not_affect_unrelated_endpoint() {
    // Endpoint caps are multi-owner (send cap is delegated cross-process during
    // spawn).  Revoking a cap for one endpoint must clear only that cnode slot and
    // must NOT destroy the endpoint object, nor disturb a second, unrelated
    // endpoint.
    std::thread::Builder::new()
        .name("stage24_ep_revoke_isolation".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let cnode = state.current_task_cnode().expect("task0 cnode");

            let (ep_a, _send_a, recv_a) = state.create_endpoint(4).expect("endpoint A");
            let (ep_b, _send_b, _recv_b) = state.create_endpoint(4).expect("endpoint B");
            assert_ne!(ep_a, ep_b, "two distinct endpoints");

            let gen_a_before = state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_a]);
            let gen_b_before = state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_b]);

            // Revoke one cap (the receive cap) of endpoint A.
            state
                .revoke_capability_in_cnode(cnode, recv_a)
                .expect("revoke recv cap A");

            // Endpoint A object must still exist (multi-owner: send cap still live),
            // and its generation must be unchanged (revoke does not destroy it).
            assert!(
                state.with_ipc_state(|ipc| ipc.endpoints[ep_a].is_some()),
                "endpoint A object must survive single-cap revoke (multi-owner)"
            );
            assert_eq!(
                state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_a]),
                gen_a_before,
                "endpoint A generation must be unchanged by cap revoke"
            );

            // Endpoint B must be entirely unaffected.
            assert!(
                state.with_ipc_state(|ipc| ipc.endpoints[ep_b].is_some()),
                "unrelated endpoint B must remain present"
            );
            assert_eq!(
                state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_b]),
                gen_b_before,
                "unrelated endpoint B generation must be unchanged"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_transfer_envelope_double_take_is_harmless() {
    // Invariant 1/12: an envelope is consumed exactly once; a second take returns
    // None and does not double-decrement the pin_refcount.
    let mut state = Bootstrap::init().expect("init");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let handle = state
        .stash_transfer_envelope(
            ThreadId(0),
            mem_cap,
            endpoint,
            None,
            Some(TransferSharedRegion {
                offset: 0x2000,
                len: PAGE_SIZE as u64,
            }),
        )
        .expect("stash");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        1
    );

    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(0))
            .is_some()
    );
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        0,
        "pin_refcount must drop to 0 after take"
    );
    // Second take is a no-op: returns None, pin_refcount stays 0 (no underflow).
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(0))
            .is_none()
    );
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        0,
        "double take must not underflow pin_refcount"
    );
}

#[test]
fn stage20_failed_transfer_send_cleans_envelope_and_keeps_refcount() {
    // Invariant 1/3: ipc_send_with_cap_transfer error-path takes back the envelope
    // (cleaned exactly once) and the source cap_refcount is unchanged (cap stays
    // with the sender; nothing was minted into a receiver).
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let before = {
        let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
        state.memory.memory_objects[slot].expect("obj").cap_refcount
    };

    // Directly model the stash + error cleanup contract: stash, then take back.
    let handle = state
        .stash_transfer_envelope(ThreadId(0), mem_cap, endpoint, Some(ThreadId(1)), None)
        .expect("stash");
    let t_created = state.ipc_path_telemetry().transfer_records_created;
    // Error path takes the envelope back with the bound receiver tid.
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(1))
            .is_some(),
        "error cleanup must take the envelope exactly once"
    );
    let t_mat = state.ipc_path_telemetry().transfer_records_materialized;
    assert!(t_mat >= 1 && t_created >= 1);

    let after = {
        let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
        state.memory.memory_objects[slot].expect("obj").cap_refcount
    };
    assert_eq!(
        after, before,
        "failed transfer must not change source cap_refcount"
    );
}

#[test]
fn stage20_active_transfer_mapping_is_two_phase_and_refcount_safe() {
    // Invariant 11: active-transfer mappings register/remove cleanly and the
    // backing MemoryObject cap_refcount is governed only by cap mint/revoke, not by
    // mapping registration.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    let refcount = state.memory.memory_objects[slot].expect("obj").cap_refcount;
    assert_eq!(refcount, 2);

    state
        .register_active_transfer_mapping(ThreadId(1), derived, VirtAddr(0x9000), PAGE_SIZE)
        .expect("register");
    // Registration must not change cap_refcount.
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "mapping registration must not touch cap_refcount"
    );
    assert!(
        state
            .active_transfer_mapping_for(ThreadId(1), derived)
            .is_some()
    );

    assert!(state.remove_active_transfer_mapping(ThreadId(1), derived));
    assert!(
        state
            .active_transfer_mapping_for(ThreadId(1), derived)
            .is_none(),
        "mapping must be removed exactly once"
    );
    // Removal of a non-existent mapping is a harmless false.
    assert!(!state.remove_active_transfer_mapping(ThreadId(1), derived));
}

#[test]
fn stage20_reply_cap_creation_does_not_change_memory_cap_refcount() {
    // Invariant 9/10: reply-cap creation mints a Reply object (no MemoryObject), so
    // no MemoryObject cap_refcount changes; recv-v2 reply-cap metadata is unaffected
    // by unrelated MemoryObject allocations.
    std::thread::Builder::new()
        .name("stage20_reply_cap_no_mem_refcount".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (mo_id, _mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
            let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
            let before = state.memory.memory_objects[slot].expect("obj").cap_refcount;

            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");

            let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
            let after = state.memory.memory_objects[slot].expect("obj").cap_refcount;
            assert_eq!(
                before, after,
                "reply-cap creation must not touch MemoryObject cap_refcount"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

// ── End Stage 16 timeout/deadline/block-state tests ───────────────────────────

// ── Stage 21: notification / IRQ-route lifetime tests ─────────────────────────

/// Set `tid` to `Blocked(EndpointReceive(0))` to model a task parked on a
/// notification recv, without driving the full block path. Mirrors the
/// injection idiom used by the Stage 16 waiter-cleanup tests.
#[cfg(test)]
fn stage21_block_on_notification(state: &mut KernelState, tid: u64) {
    state
        .with_tcbs_mut(|tcbs| {
            let tcb = tcbs
                .iter_mut()
                .flatten()
                .find(|t| t.tid.0 == tid)
                .expect("tcb");
            tcb.status = TaskStatus::Blocked(WaitReason::EndpointReceive(CapId(0)));
            Ok::<_, KernelError>(())
        })
        .expect("block");
}

#[test]
fn stage21_signal_wakes_waiting_task_exactly_once() {
    // route_external_irq -> signal_notification must wake a Blocked waiter once
    // (Blocked -> Runnable, waiter slot consumed). A second IRQ with no waiter
    // registered must not re-wake or re-enqueue anything.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2101).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(9, notif_cap).expect("bind");

    stage21_block_on_notification(&mut state, 2101);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2101));
    });
    assert!(state.task_is_blocked(2101), "waiter blocked before signal");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        1,
        "waiter present"
    );

    state.route_external_irq(9).expect("irq");
    assert!(state.task_is_runnable(2101), "waiter woken to Runnable");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "waiter slot consumed by signal"
    );

    // Second IRQ: no registered waiter, task already Runnable, must stay Runnable.
    state.route_external_irq(9).expect("irq2");
    assert!(state.task_is_runnable(2101), "no double-wake");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "still no waiter"
    );
}

#[test]
fn stage21_signal_skips_dead_waiter_safely() {
    // A stale Dead-task TID lingering in notification_waiters must NOT be
    // resurrected to Runnable by a signal.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2102).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(10, notif_cap).expect("bind");

    state.mark_task_dead(2102).expect("dead");
    assert!(state.task_is_dead(2102), "dead before injection");
    // Simulate a stale waiter reference surviving (defence-in-depth).
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2102));
    });

    state.route_external_irq(10).expect("irq");
    assert!(
        state.task_is_dead(2102),
        "Dead task must not be resurrected by signal_notification"
    );
}

#[test]
fn stage21_signal_skips_exited_waiter_safely() {
    // Same as above for an Exited task.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2103).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(11, notif_cap).expect("bind");

    state.exit_task(2103, 0).expect("exit");
    assert!(state.task_is_exited(2103), "exited before injection");
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2103));
    });

    state.route_external_irq(11).expect("irq");
    assert!(
        state.task_is_exited(2103),
        "Exited task must not be resurrected by signal_notification"
    );
}

#[test]
fn stage21_exit_task_clears_notification_waiter() {
    // exit_task -> clear_ipc_waiters_for_tid must drop the notification waiter.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2104).expect("task");
    let (notif_idx, _cap, _recv) = state.create_notification(4).expect("notif");
    stage21_block_on_notification(&mut state, 2104);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2104));
    });
    assert_eq!(state.notification_waiter_count(notif_idx), 1, "before exit");

    state.exit_task(2104, 7).expect("exit");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "notification waiter cleared by exit_task"
    );
}

#[test]
fn stage21_mark_task_dead_clears_notification_waiter() {
    // mark_task_dead must also clear the notification waiter slot.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2105).expect("task");
    let (notif_idx, _cap, _recv) = state.create_notification(4).expect("notif");
    stage21_block_on_notification(&mut state, 2105);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2105));
    });
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        1,
        "before death"
    );

    state.mark_task_dead(2105).expect("dead");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "notification waiter cleared by mark_task_dead"
    );
}

#[test]
fn stage21_destroy_notification_clears_waiter_and_invalidates_caps() {
    // destroy_notification with an active waiter must: clear the waiter slot,
    // remove the object, and bump generation so the SIGNAL cap goes stale.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2106).expect("task");
    let (notif_idx, _notif_cap, _recv) = state.create_notification(4).expect("notif");
    let gen_before = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    // A live notification cap is one whose object generation matches.
    let live_object = CapObject::Notification {
        index: notif_idx,
        generation: gen_before,
    };
    assert!(
        state.capability_object_live(live_object).is_some(),
        "notification cap live before destroy"
    );
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2106));
    });

    let waiter = state.destroy_notification(notif_idx).expect("destroy");
    assert_eq!(
        waiter,
        Some(ThreadId(2106)),
        "destroy returns snapshotted waiter"
    );
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "waiter slot cleared by destroy"
    );
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "object removed by destroy"
    );
    let gen_after = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    assert_ne!(gen_before, gen_after, "generation bumped on destroy");

    // The capability minted at the pre-destroy generation must now be non-live.
    assert!(
        state.capability_object_live(live_object).is_none(),
        "destroyed notification cap must be non-live (generation mismatch)"
    );
}

#[test]
fn stage21_signal_before_wait_leaves_pending_for_later_recv() {
    // Signal-before-wait: an IRQ delivered while no task waits must leave a
    // pending entry that a subsequent recv consumes (no waiter woken).
    let mut state = Bootstrap::init().expect("init");
    let (_notif_idx, notif_cap, recv_cap) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(12, notif_cap).expect("bind");

    // No waiter registered yet.
    state.route_external_irq(12).expect("irq");

    // The pending IRQ is delivered by a non-blocking recv.
    let msg = state.try_ipc_recv(recv_cap).expect("recv");
    assert!(msg.is_some(), "pending IRQ delivered to later recv");
    // No further pending entries.
    let again = state.try_ipc_recv(recv_cap).expect("recv2");
    assert!(again.is_none(), "no spurious second delivery");
}

#[test]
fn stage21_wait_before_signal_registers_then_wakes() {
    // Wait-before-signal: the waiter is registered first, then a signal wakes it.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2108).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(13, notif_cap).expect("bind");

    stage21_block_on_notification(&mut state, 2108);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2108));
    });
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        1,
        "waiter registered"
    );
    assert!(state.task_is_blocked(2108), "blocked before signal");

    state.route_external_irq(13).expect("irq");
    assert!(state.task_is_runnable(2108), "signal woke waiter");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "waiter consumed"
    );
}

#[test]
fn stage21_repeated_signal_accumulates_pending() {
    // Repeated signals with no waiter must accumulate pending IRQs up to depth,
    // each consumable by recv in order (FIFO).
    let mut state = Bootstrap::init().expect("init");
    let (_notif_idx, notif_cap, recv_cap) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(14, notif_cap).expect("bind");

    state.route_external_irq(14).expect("irq1");
    state.route_external_irq(14).expect("irq2");
    state.route_external_irq(14).expect("irq3");

    // Three pending entries, delivered in order, then drained.
    for _ in 0..3 {
        assert!(
            state.try_ipc_recv(recv_cap).expect("recv").is_some(),
            "pending IRQ present"
        );
    }
    assert!(
        state.try_ipc_recv(recv_cap).expect("recv").is_none(),
        "queue drained after three signals"
    );
}

#[test]
fn stage21_irq_route_registration_and_teardown() {
    // bind_irq_notification registers a route; destroy_notification tears down
    // every route targeting the destroyed notification.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(15, notif_cap).expect("bind");

    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[15]),
        Some(notif_idx),
        "route registered to notification"
    );

    state.destroy_notification(notif_idx).expect("destroy");
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[15]),
        None,
        "route torn down by destroy_notification"
    );
}

#[test]
fn stage21_irq_delivery_to_destroyed_notification_is_safe_noop() {
    // After a notification is destroyed, a hardware IRQ that still references it
    // (defence-in-depth: route forced to survive) must be a benign no-op, not a
    // kernel error.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(16, notif_cap).expect("bind");

    state.destroy_notification(notif_idx).expect("destroy");
    // Normal path: route was cleared, so this is an immediate no-op.
    state.route_external_irq(16).expect("noop after destroy");

    // Defence-in-depth: force a stale route back at the freed slot and confirm
    // signal_notification reports the dead object as a swallowed no-op.
    state.with_ipc_state_mut(|ipc| {
        ipc.irq_routes[16] = Some(notif_idx);
    });
    state
        .route_external_irq(16)
        .expect("stale route to destroyed notification must be a no-op, not an error");
}

// ── End Stage 21 notification / IRQ-route lifetime tests ──────────────────────

// ── Stage 22: destroy_notification wiring into cap revoke / cnode teardown ────
//
// Ownership decision: Notification caps are single-owner per object — the
// creator mints exactly one SIGNAL + one RECEIVE cap into its own cnode (see
// `create_notification`), Notification caps are never granted cross-process,
// and there is no refcount. Revoking ANY Notification cap therefore destroys
// the underlying object immediately. `destroy_notification` is idempotent, so
// revoking the paired cap (or a double-revoke) is a benign WrongObject no-op.

#[test]
fn stage22_notification_cap_revoke_destroys_object() {
    // Revoking a Notification cap frees the object slot and bumps the generation.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    let gen_before = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_some()),
        "object present before revoke"
    );

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "notification object freed by cap revoke"
    );
    let gen_after = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    assert_ne!(gen_before, gen_after, "generation bumped on revoke-destroy");
    let live = CapObject::Notification {
        index: notif_idx,
        generation: gen_before,
    };
    assert!(
        state.capability_object_live(live).is_none(),
        "pre-revoke generation no longer live"
    );
}

#[test]
fn stage22_notification_cap_revoke_tears_down_irq_route() {
    // Revoking a Notification cap removes any IRQ route targeting it.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(20, notif_cap).expect("bind");
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[20]),
        Some(notif_idx),
        "route registered before revoke"
    );

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[20]),
        None,
        "IRQ route torn down by cap revoke"
    );
}

#[test]
fn stage22_notification_cap_revoke_clears_waiter() {
    // Revoking a Notification cap clears a parked waiter and wakes it (Blocked ->
    // Runnable), mirroring the signal-path Blocked-only wake guard.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2201).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    stage21_block_on_notification(&mut state, 2201);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2201));
    });
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        1,
        "waiter before revoke"
    );
    assert!(state.task_is_blocked(2201), "blocked before revoke");

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "waiter slot cleared by revoke-destroy"
    );
    assert!(
        state.task_is_runnable(2201),
        "Blocked waiter woken to Runnable by revoke-destroy"
    );
}

