#[test]
fn stage22_create_notification_after_revoke_reuses_slot_cleanly() {
    // After revoke+destroy, a fresh create reusing the same slot starts clean:
    // no stale waiter, no inherited route, fresh generation, live cap.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(23, notif_cap).expect("bind");
    let gen_first = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    let (new_idx, new_cap, _new_recv) = state.create_notification(4).expect("recreate");
    assert_eq!(new_idx, notif_idx, "lowest free slot reused");
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[23]),
        None,
        "no route inherited by reused slot"
    );
    assert_eq!(
        state.notification_waiter_count(new_idx),
        0,
        "no stale waiter on reused slot"
    );
    let gen_new = state.with_ipc_state(|ipc| ipc.notification_generations[new_idx]);
    assert_ne!(gen_first, gen_new, "fresh generation on reused slot");
    let new_obj = state
        .current_task_capability(new_cap)
        .expect("new cap resolves")
        .object;
    assert!(
        state.capability_object_live(new_obj).is_some(),
        "freshly created cap is live"
    );
}

#[test]
fn stage22_double_revoke_notification_cap_is_safe() {
    // First revoke destroys the object; revoking the (now empty) slot a second
    // time is a safe error, never a double-destroy or panic.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    let cnode = state.current_task_cnode().expect("cnode");

    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("first revoke");
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "object gone after first revoke"
    );
    let gen_after_first = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);

    // Second revoke of the now-empty slot: InvalidCapability (slot cleared), and
    // destroy_notification's WrongObject is swallowed — no extra generation bump.
    let second = state.revoke_capability_in_cnode(cnode, notif_cap);
    assert!(
        second.is_err(),
        "second revoke of empty slot errors: {second:?}"
    );
    let gen_after_second = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    assert_eq!(
        gen_after_first, gen_after_second,
        "no double-destroy: generation unchanged by second revoke"
    );
}

#[test]
fn stage22_notification_cap_revoke_does_not_affect_unrelated_notification() {
    // Revoking one notification's cap must not disturb a second, unrelated
    // notification (object, route, generation all intact).
    let mut state = Bootstrap::init().expect("init");
    let (idx_a, cap_a, _recv_a) = state.create_notification(4).expect("notif a");
    let (idx_b, cap_b, recv_b) = state.create_notification(4).expect("notif b");
    assert_ne!(idx_a, idx_b, "distinct slots");
    state.bind_irq_notification(24, cap_a).expect("bind a");
    state.bind_irq_notification(25, cap_b).expect("bind b");
    let gen_b_before = state.with_ipc_state(|ipc| ipc.notification_generations[idx_b]);

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, cap_a)
        .expect("revoke a");

    // A torn down, B intact.
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[idx_a].is_none()),
        "A destroyed"
    );
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[idx_b].is_some()),
        "B still alive"
    );
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[25]),
        Some(idx_b),
        "B route untouched"
    );
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.notification_generations[idx_b]),
        gen_b_before,
        "B generation untouched"
    );
    // B still delivers: signal via its route, drain via its recv cap.
    state.route_external_irq(25).expect("irq b");
    assert!(
        state.try_ipc_recv(recv_b).expect("recv b").is_some(),
        "B still delivers after A revoked"
    );
}

// ── End Stage 22 destroy_notification wiring tests ────────────────────────────

// ── Stage 23: notification live revoke/release surface audit ──────────────────
//
// Audit result (see KERNEL_LOCKING.md §41): there is NO generic user-facing
// capability-release / capability-revoke syscall. SYSCALL_COUNT == 32 (stage 42+43), 23 live
// Syscall variants. The only release-shaped syscall is `TransferRelease`
// (NR = 4), which is MemoryObject/transfer-scoped: `handle_transfer_release`
// resolves an active transfer mapping for the cap and errors out before
// `revoke_capability_in_cnode` when none exists. A Notification cap never has an
// active transfer mapping, so `TransferRelease` cannot revoke (and therefore
// cannot destroy) a Notification object.
//
// `create_notification` has no syscall caller, so notifications are never created
// or released from userspace on the live boot path. Notification teardown is
// reachable only through:
//   - the direct revoke helpers (`revoke_capability_in_cnode` /
//     `revoke_capability_direct_in_process_cnode`), and
//   - the task/process-exit cnode-teardown path
//     (`maybe_cleanup_process_cnode_for_pid`), which is the closest live-path
//     equivalent.
//
// These tests pin those facts down without faking a live cap-release syscall.

#[test]
fn stage23_revoke_notification_cap_destroys_object_and_routes() {
    // Direct revoke helper (the only reachable teardown surface): revoking a
    // Notification cap frees the object AND tears down its IRQ route in one pass.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(31, notif_cap).expect("bind");
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_some()),
        "object present before revoke"
    );
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[31]),
        Some(notif_idx),
        "route registered before revoke"
    );

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "object freed by revoke"
    );
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[31]),
        None,
        "IRQ route torn down by revoke"
    );
}

#[test]
fn stage23_cnode_cleanup_on_task_exit_destroys_notification() {
    // Closest live-path equivalent: task exit -> mark_task_dead ->
    // maybe_cleanup_process_cnode_for_pid revokes every live cap in the dying
    // task's cnode (including its Notification caps), which fires the Stage 22
    // teardown. This is the only live-reachable path to notification teardown.
    let mut state = Bootstrap::init().expect("init");
    let pid = state.current_tid().expect("current tid");
    let (notif_idx, _notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(32, _notif_cap).expect("bind");
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_some()),
        "object present before exit"
    );

    state.mark_task_dead(pid).expect("dead");
    state.maybe_cleanup_process_cnode_for_pid(pid);

    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "object freed by task-exit cnode cleanup"
    );
    assert_eq!(
        state.with_ipc_state(|ipc| ipc.irq_routes[32]),
        None,
        "IRQ route torn down by task-exit cnode cleanup"
    );
}

#[test]
fn stage23_notification_cleanup_idempotent_double_revoke() {
    // Idempotency on the only reachable teardown surface: first revoke destroys
    // the object; a second revoke of the now-empty slot is a safe error with no
    // double-destroy and no spurious second generation bump.
    let mut state = Bootstrap::init().expect("init");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    let cnode = state.current_task_cnode().expect("cnode");

    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("first revoke");
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_none()),
        "object gone after first revoke"
    );
    let gen_after_first = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);

    let second = state.revoke_capability_in_cnode(cnode, notif_cap);
    assert!(
        second.is_err(),
        "second revoke of empty slot errors: {second:?}"
    );
    let gen_after_second = state.with_ipc_state(|ipc| ipc.notification_generations[notif_idx]);
    assert_eq!(
        gen_after_first, gen_after_second,
        "idempotent: no double-destroy, generation unchanged by second revoke"
    );
}

#[test]
fn stage23_transfer_release_syscall_cannot_target_notification_cap() {
    // The only user-facing release syscall is TransferRelease (NR = 4). Its
    // handler is MemoryObject/transfer-scoped: it requires an active transfer
    // mapping for the cap. A Notification cap never has one, so the handler's
    // gate (`active_transfer_mapping_for`) returns None and the syscall errors
    // out BEFORE revoke — it cannot destroy a Notification object.
    let mut state = Bootstrap::init().expect("init");
    let owner = ThreadId(state.current_tid().expect("current tid"));
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");

    // Precondition the live TransferRelease handler checks: no transfer mapping.
    assert_eq!(
        state.active_transfer_mapping_for(owner, notif_cap),
        None,
        "Notification cap has no active transfer mapping (TransferRelease gate fails)"
    );

    // The Notification object remains alive — no live release syscall touched it.
    assert!(
        state.with_ipc_state(|ipc| ipc.notifications[notif_idx].is_some()),
        "notification object untouched by any user release-syscall surface"
    );

    // ABI guard: the release surface is exactly the 30-slot table; no cap-release
    // syscall number was added.
    assert_eq!(
        crate::kernel::syscall::SYSCALL_COUNT,
        32,
        "SYSCALL_COUNT unchanged"
    );
}

#[test]
fn stage23_stale_notification_cap_after_revoke_cannot_signal_or_recv() {
    // After teardown via the reachable revoke path, the old caps are dead: an IRQ
    // on the (now-cleared) route is a benign no-op, and a recv via the stale
    // RECEIVE cap is a stable error — a stale cap cannot signal or drain.
    let mut state = Bootstrap::init().expect("init");
    let (_notif_idx, notif_cap, recv_cap) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(33, notif_cap).expect("bind");

    let cnode = state.current_task_cnode().expect("cnode");
    state
        .revoke_capability_in_cnode(cnode, notif_cap)
        .expect("revoke");

    // Signal attempt via the old IRQ line: route is gone -> benign no-op, twice.
    state.route_external_irq(33).expect("stale signal noop 1");
    state.route_external_irq(33).expect("stale signal noop 2");

    // Drain attempt via the stale RECEIVE cap: stable error, never a panic.
    let first = state.try_ipc_recv(recv_cap);
    assert!(first.is_err(), "stale recv cap errors: {first:?}");
    let second = state.try_ipc_recv(recv_cap);
    assert_eq!(first, second, "stale recv error is stable across calls");
}

#[test]
fn stage23_no_live_notification_release_syscall_documented() {
    // Documentation gate (audit lock-down): there is no generic user-facing
    // capability-release / capability-revoke syscall, and `create_notification`
    // has no syscall caller, so userspace cannot create or release a Notification
    // cap on the live boot path. Notification teardown is reachable only via the
    // direct revoke helpers and the task/process-exit cnode-teardown path. A live
    // notification create/release syscall would require a new syscall number,
    // which is out of scope by the hard ABI invariant (SYSCALL_COUNT frozen).
    // See KERNEL_LOCKING.md §41.
    assert_eq!(
        crate::kernel::syscall::SYSCALL_COUNT,
        32,
        "no cap-release syscall added; SYSCALL_COUNT frozen"
    );
    assert!(
        true,
        "no live user-facing notification release/revoke syscall exists; \
         teardown reachable only via revoke helpers + task-exit cnode cleanup \
         (deferred: live notification create/release syscall surface)"
    );
}

// ── End Stage 23 notification revoke/release surface audit tests ───────────────

// ── Stage 25C: replier-exit reply-record cleanup ──────────────────────────────

#[test]
fn stage25c_replier_exit_clears_global_reply_record() {
    // revoke_reply_caps_for_replier (wired into mark_task_dead) must clear the
    // global ReplyCapRecord keyed on responder_tid when the replier tears down,
    // even though the caller is still alive.
    std::thread::Builder::new()
        .name("stage25c_replier_exit".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            // The recv cap must resolve in the caller's (task 1) cnode.
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            // Caller = task 1, replier (responder) = task 2.
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");
            assert!(
                state.reply_cap_record_present(0),
                "precondition: global reply record present (caller=1, replier=2)"
            );

            // Replier (task 2) dies while caller (task 1) is still alive.
            state.mark_task_dead(2).expect("mark replier dead");

            assert!(
                !state.reply_cap_record_present(0),
                "replier teardown must clear the global reply record keyed on responder_tid"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_caller_exit_still_clears_global_reply_record() {
    // Regression guard: adding the replier-side revoke must not break the
    // existing caller-side clearing. Caller teardown still clears its record.
    std::thread::Builder::new()
        .name("stage25c_caller_exit".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");
            assert!(state.reply_cap_record_present(0));

            // Caller (task 1) dies first.
            state.mark_task_dead(1).expect("mark caller dead");

            assert!(
                !state.reply_cap_record_present(0),
                "caller teardown must still clear the global reply record"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_caller_exits_first_then_replier_exit_is_idempotent() {
    // Caller exits first (clears the record); the later replier teardown finds
    // the slot already None and is a no-op (no underflow, no panic).
    std::thread::Builder::new()
        .name("stage25c_caller_first_replier_idem".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");

            state.mark_task_dead(1).expect("caller dead");
            assert!(
                !state.reply_cap_record_present(0),
                "record cleared by caller exit"
            );

            // Replier teardown: slot already None → 0 revoked, no-op.
            let revoked = state.revoke_reply_caps_for_replier(2);
            assert_eq!(
                revoked, 0,
                "replier revoke after caller cleared must be a no-op"
            );
            state.mark_task_dead(2).expect("replier dead is idempotent");
            assert!(!state.reply_cap_record_present(0));
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_replier_exits_first_then_caller_cleanup_is_idempotent() {
    // Replier exits first (clears the record via the new path); the later caller
    // teardown finds the slot already None and is a no-op.
    std::thread::Builder::new()
        .name("stage25c_replier_first_caller_idem".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");

            state.mark_task_dead(2).expect("replier dead");
            assert!(
                !state.reply_cap_record_present(0),
                "record cleared by replier exit"
            );

            // Caller teardown: slot already None → 0 revoked, no-op.
            let revoked = state.revoke_reply_caps_for_caller(1);
            assert_eq!(
                revoked, 0,
                "caller revoke after replier cleared must be a no-op"
            );
            state.mark_task_dead(1).expect("caller dead is idempotent");
            assert!(!state.reply_cap_record_present(0));
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_both_exit_no_leak_no_underflow() {
    // Both helpers running in one teardown (mark_task_dead calls both
    // for_caller and for_replier): the second sees the slot already None.
    // No leak (record gone), no underflow (revoke counts are sane).
    std::thread::Builder::new()
        .name("stage25c_both_exit".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("self task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            // Caller and replier are the same task (self-reply edge case).
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, Some(ThreadId(1)))
                .expect("create reply cap");
            assert!(state.reply_cap_record_present(0));

            // mark_task_dead(1) runs both revoke_reply_caps_for_caller(1) and
            // revoke_reply_caps_for_replier(1); the first clears, the second no-ops.
            state.mark_task_dead(1).expect("mark dead");
            assert!(
                !state.reply_cap_record_present(0),
                "record must be gone, not leaked"
            );

            // Re-running both directly is still a clean no-op.
            assert_eq!(state.revoke_reply_caps_for_caller(1), 0);
            assert_eq!(state.revoke_reply_caps_for_replier(1), 0);
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_stale_waiter_cap_id_cleared_on_replier_teardown() {
    // A materialized waiter_cap_id pointing into the replier's cnode must not
    // outlive the replier: once the replier tears down, the whole record (and
    // thus its waiter_cap_id) is gone.
    std::thread::Builder::new()
        .name("stage25c_stale_waiter_cap".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            // Caller = task 0 (current), replier = task 2.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");
            let reply_index = 0usize;
            let reply_gen = state.with_ipc_state(|ipc| ipc.reply_cap_generations[reply_index]);
            state.set_reply_cap_waiter_cap(reply_index, reply_gen, reply_cap);
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap),
                "precondition: waiter_cap_id set"
            );

            state.mark_task_dead(2).expect("replier dead");

            assert!(
                !state.reply_cap_record_present(reply_index),
                "replier teardown clears the record; the stale waiter_cap_id is gone with it"
            );
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                None,
                "no lingering waiter_cap_id after replier teardown"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_reply_cap_cannot_be_reused_after_replier_teardown() {
    // After the replier is torn down the global record is gone, so the Reply
    // CapId is stale: ipc_reply must return a stable StaleCapability error.
    std::thread::Builder::new()
        .name("stage25c_no_reuse_after_replier_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            // Reply cap minted into the current (task 0) cnode; responder = task 2.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, Some(ThreadId(2)))
                .expect("create reply cap");

            state.mark_task_dead(2).expect("replier dead");

            assert_eq!(
                state.ipc_reply(reply_cap, Message::new(0, b"stale").expect("msg")),
                Err(KernelError::StaleCapability),
                "stale reply cap after replier teardown must be a stable error"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_unrelated_reply_record_unaffected() {
    // revoke_reply_caps_for_replier must only clear records whose responder_tid
    // matches; an unrelated record (different replier) survives.
    std::thread::Builder::new()
        .name("stage25c_unrelated_record".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(2).expect("replier 2");
            state.register_task(3).expect("replier 3");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            // Record A: replier = task 2 (slot 0).
            let _reply_a = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, Some(ThreadId(2)))
                .expect("reply A");
            // Record B: replier = task 3 (slot 1).
            let _reply_b = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, Some(ThreadId(3)))
                .expect("reply B");
            assert!(state.reply_cap_record_present(0));
            assert!(state.reply_cap_record_present(1));

            // Tear down replier 2 only.
            let revoked = state.revoke_reply_caps_for_replier(2);
            assert_eq!(
                revoked, 1,
                "exactly the one record for replier 2 must be cleared"
            );
            assert!(
                !state.reply_cap_record_present(0),
                "replier-2 record cleared"
            );
            assert!(
                state.reply_cap_record_present(1),
                "unrelated replier-3 record must be unaffected"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage25c_cnode_teardown_with_reply_cap_remains_safe() {
    // Full mark_task_dead path (which includes cnode teardown via
    // maybe_cleanup_process_cnode_for_pid) with a reply cap held by the dying
    // replier must remain safe: record cleared, no panic, generation guard intact.
    std::thread::Builder::new()
        .name("stage25c_cnode_teardown_safe".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            state.register_task(2).expect("replier task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            // Grant the receive cap to the caller (task 1) so create_reply_cap_for_caller
            // can resolve it, and also to the replier (task 2) so it owns a cnode cap.
            let recv_cap_t1 = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _recv_cap_t2 = state
                .grant_capability_task_to_task(0, recv_cap_global, 2)
                .expect("grant recv to t2");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap_t1, Some(ThreadId(2)))
                .expect("create reply cap");
            assert!(state.reply_cap_record_present(0));

            // Full teardown of the replier (clears record + cnode).
            state.mark_task_dead(2).expect("mark replier dead");

            assert!(
                !state.reply_cap_record_present(0),
                "record cleared after full replier teardown"
            );
            // Caller teardown afterward is still a clean no-op.
            state.mark_task_dead(1).expect("mark caller dead");
            assert!(!state.reply_cap_record_present(0));
        })
        .expect("spawn")
        .join()
        .expect("join");
}

