            ORACLE_SCRIPT.contains("proof_require \"queued-split\" \"IPC_RECV_PROOF_QUEUED_SPLIT_SEQUENCE_DONE\" \"IPC_RECV_V2_META_QUEUED_SPLIT_OK\"")
